import React from 'react';
import { Link } from 'react-router-dom';

const SchoolHeader = () => {
    return (
        <div className="bg-gradient-to-r from-blue-900 via-blue-800 to-blue-900 text-white py-3 px-4 shadow-lg">
            <div className="max-w-7xl mx-auto">
                <div className="flex flex-col md:flex-row justify-between items-center text-center md:text-left">
                    {/* School Name & Event */}
                    <div className="mb-2 md:mb-0">
                        <h1 className="text-xl md:text-2xl font-bold tracking-wider">
                            🏫 Podar International School, Latur
                        </h1>
                        <p className="text-sm md:text-base text-blue-200 font-medium">
                            Khadgoan Ring Road
                        </p>
                    </div>
                    
                    {/* Event Details */}
                    <div className="flex flex-col md:flex-row items-center gap-2 md:gap-6">
                        <div className="bg-yellow-500 text-blue-900 px-4 py-1 rounded-full font-bold text-sm md:text-base">
                            ⚡ Spark 4.0
                        </div>
                        <div className="text-sm md:text-base text-blue-200">
                            Science Fair 2026-27
                        </div>
                        <div className="hidden md:block text-blue-300 text-sm">
                            🗓️ 2026-27
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default SchoolHeader;
